410→ */
411→export async function getProjectFeatureUsage(
412→	orgId: string,
413→	projectPath: string,
414→	days = 30,
415→): Promise<ProjectFeatureUsage> {
416→	const org = escapeString(orgId);
417→	const pp = escapeString(projectPath);
418→	const d = Number(days);
419→
420→	const pkSubquery = `(
421→    SELECT if(git_remote != '', git_remote, repository) as pk
422→    FROM rudel.session_analytics
423→    WHERE project_path = '${pp}'
424→      AND (git_remote != '' OR repository != '')
425→      AND organization_id = '${org}'
426→    LIMIT 1
427→  )`;
428→
429→	const adoptionQuery = `
430→    SELECT
431→      COUNT(*) as total_sessions,
432→      countIf(length(subagent_types) > 0) as subagents_sessions,
433→      countIf(length(skills) > 0) as skills_sessions,
434→      countIf(length(slash_commands) > 0) as slash_commands_sessions
435→    FROM rudel.session_analytics
436→    WHERE if(git_remote != '', git_remote, repository) = ${pkSubquery}
437→    AND ${buildDateFilter(d)}
438→    AND organization_id = '${org}'
439→  `;
440→
441→	const topSubagentsQuery = `
442→    SELECT val as name, count() as count
443→    FROM rudel.session_analytics
444→    ARRAY JOIN subagent_types as val
445→    WHERE if(git_remote != '', git_remote, repository) = ${pkSubquery}
446→      AND ${buildDateFilter(d)}
447→      AND organization_id = '${org}'
448→      AND val != ''
449→    GROUP BY val
450→    ORDER BY count DESC
451→    LIMIT 10
452→  `;
453→
454→	const topSkillsQuery = `
455→    SELECT val as name, count() as count
456→    FROM rudel.session_analytics
457→    ARRAY JOIN skills as val
458→    WHERE if(git_remote != '', git_remote, repository) = ${pkSubquery}
459→      AND ${buildDateFilter(d)}
460→      AND organization_id = '${org}'
461→      AND val != ''
462→    GROUP BY val
463→    ORDER BY count DESC
464→    LIMIT 10
465→  `;
466→
467→	const topSlashCommandsQuery = `
468→    SELECT val as name, count() as count
469→    FROM rudel.session_analytics
470→    ARRAY JOIN slash_commands as val
471→    WHERE if(git_remote != '', git_remote, repository) = ${pkSubquery}
472→      AND ${buildDateFilter(d)}
473→      AND organization_id = '${org}'
474→      AND val != ''
475→    GROUP BY val
476→    ORDER BY count DESC
477→    LIMIT 10
478→  `;
479→
480→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
481→		await Promise.all([
482→			queryClickhouse<{
483→				total_sessions: number;
484→				subagents_sessions: number;
485→				skills_sessions: number;
486→				slash_commands_sessions: number;
487→			}>(adoptionQuery),
488→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
489→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
490→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
491→		]);
492→
493→	if (adoptionResults.length === 0) {
494→		return {
495→			subagents_adoption_rate: 0,
496→			skills_adoption_rate: 0,
497→			slash_commands_adoption_rate: 0,
498→			top_subagents: [],
499→			top_skills: [],
500→			top_slash_commands: [],
501→		};
502→	}
503→
504→	const [stats] = adoptionResults;
505→	if (!stats)
506→		return {
507→			subagents_adoption_rate: 0,
508→			skills_adoption_rate: 0,
509→			slash_commands_adoption_rate: 0,
510→			top_subagents: [],
511→			top_skills: [],
512→			top_slash_commands: [],
513→		};
514→	return {
515→		subagents_adoption_rate:
516→			stats.total_sessions > 0
517→				? (stats.subagents_sessions / stats.total_sessions) * 100
518→				: 0,
519→		skills_adoption_rate:
520→			stats.total_sessions > 0
521→				? (stats.skills_sessions / stats.total_sessions) * 100
522→				: 0,
523→		slash_commands_adoption_rate:
524→			stats.total_sessions > 0
525→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
526→				: 0,
527→		top_subagents: topSubagents,
528→		top_skills: topSkills,
529→		top_slash_commands: topSlashCommands,
530→	};
531→}
