  1→import { join } from "node:path";
  2→import { getLogger, withContext } from "@logtape/logtape";
  3→import { RPCHandler } from "@orpc/server/fetch";
  4→import { createAuth } from "./auth.js";
  5→import { db } from "./db.js";
  6→import { setupLogging } from "./logging.js";
  7→import { router } from "./router.js";
  8→
  9→await setupLogging();
 10→
 11→const logger = getLogger(["rudel", "api", "http"]);
 12→
 13→const socialProviders: Record<
 14→	string,
 15→	{ clientId: string; clientSecret: string }
 16→> = {};
 17→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 18→	socialProviders.google = {
 19→		clientId: process.env.GOOGLE_CLIENT_ID,
 20→		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 21→	};
 22→}
 23→if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 24→	socialProviders.github = {
 25→		clientId: process.env.GITHUB_CLIENT_ID,
 26→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 27→	};
 28→}
 29→
 30→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 31→const trustedOrigins = process.env.TRUSTED_ORIGINS
 32→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 33→	: ["http://localhost:4011"];
 34→
 35→const auth = createAuth(db, {
 36→	appURL,
 37→	secret: process.env.BETTER_AUTH_SECRET,
 38→	socialProviders,
 39→	trustedOrigins,
 40→	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 41→});
 42→
 43→const rpcHandler = new RPCHandler(router);
 44→
 45→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 46→const STATIC_DIR = join(
 47→	import.meta.dir,
 48→	"..",
 49→	process.env.STATIC_DIR ?? "public",
 50→);
 51→
 52→function corsHeaders(origin: string | null): Record<string, string> {
 53→	if (origin !== ALLOWED_ORIGIN) return {};
 54→	return {
 55→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 56→		"Access-Control-Allow-Credentials": "true",
 57→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 58→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 59→	};
 60→}
 61→
 62→const port = process.env.PORT ?? 4010;
 63→
 64→const server = Bun.serve({
 65→	port,
 66→	async fetch(request) {
 67→		const origin = request.headers.get("Origin");
 68→		const cors = corsHeaders(origin);
 69→
 70→		if (request.method === "OPTIONS") {
 71→			return new Response(null, { status: 204, headers: cors });
 72→		}
 73→
 74→		const url = new URL(request.url);
 75→
 76→		// Health check for Fly.io (must be GET-accessible)
 77→		if (url.pathname === "/health") {
 78→			return Response.json({ status: "ok", timestamp: Date.now() });
 79→		}
 80→
 81→		const requestId = crypto.randomUUID();
 82→		const start = performance.now();
 83→
 84→		return withContext(
 85→			{ requestId, method: request.method, path: url.pathname },
 86→			async () => {
 87→				const response = await handleRequest(request, url, cors);
 88→				const duration = Math.round(performance.now() - start);
 89→				logger.info("{method} {path} {status} {duration}ms", {
 90→					method: request.method,
 91→					path: url.pathname,
 92→					status: response.status,
 93→					duration,
 94→				});
 95→				return response;
 96→			},
 97→		);
 98→	},
 99→});
100→
101→async function handleRequest(
102→	request: Request,
103→	url: URL,
104→	cors: Record<string, string>,
105→): Promise<Response> {
106→	if (url.pathname === "/api/cli-token") {
107→		const session = await auth.api.getSession({
108→			headers: request.headers,
109→		});
110→		if (!session) {
111→			return new Response(JSON.stringify({ error: "Not authenticated" }), {
112→				status: 401,
113→				headers: { ...cors, "Content-Type": "application/json" },
114→			});
115→		}
116→		return new Response(JSON.stringify({ token: session.session.token }), {
117→			status: 200,
118→			headers: { ...cors, "Content-Type": "application/json" },
119→		});
120→	}
121→
122→	if (url.pathname.startsWith("/api/auth")) {
123→		const response = await auth.handler(request);
124→		for (const [key, value] of Object.entries(cors)) {
125→			response.headers.set(key, value);
126→		}
